app.post('/login', (req, res) => {
  const { email, password, client_id, redirect_uri, state, scope } = req.body;

  const user = users[email];
  if (!user || user.password !== password) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  const client = clients[client_id];
  if (!client || !client.redirect_uris.includes(redirect_uri)) {
    return res.status(400).json({ error: 'Invalid client configuration' });
  }

  const code = generateRandomString();
  const codeData = {
    client_id,
    redirect_uri,
    user: email,
    scope: scope || '',
    expires_at: Date.now() + 600000
  };

  authorizationCodes.set(code, codeData);

  setTimeout(() => {
    authorizationCodes.delete(code);
  }, 600000);

  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.append('code', code);
  if (state) {
    redirectUrl.searchParams.append('state', state);
  }

  res.json({ redirect_url: redirectUrl.toString() });
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret, refresh_token } = req.body;

  if (!grant_type) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing grant_type' });
  }

  if (grant_type === 'authorization_code') {
    if (!code || !redirect_uri || !client_id || !client_secret) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters' });
    }

    const client = clients[client_id];
    if (!client || client.client_secret !== client_secret) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
    }

    const codeData = authorizationCodes.get(code);
    if (!codeData) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code' });
    }

    if (codeData.expires_at < Date.now()) {
      authorizationCodes.delete(code);
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
    }

    if (codeData.client_id !== client_id || codeData.redirect_uri !== redirect_uri) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Code does not match client' });
    }

    authorizationCodes.delete(code);

    const accessToken = generateRandomString();
    const refreshTokenValue = generateRandomString();

    const tokenData = {
      user: codeData.user,
      client_id,
      scope: codeData.scope,
      expires_at: Date.now() + 3600000
    };

    accessTokens.set(accessToken, tokenData);
    refreshTokens.set(refreshTokenValue, {
      user: codeData.user,
      client_id,
      scope: codeData.scope
    });

    setTimeout(() => {
      accessTokens.delete(accessToken);
    }, 3600000);

    return res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: 3600,
      refresh_token: refreshTokenValue,
      scope: codeData.scope
    });

  } else if (grant_type === 'refresh_token') {
    if (!refresh_token || !client_id || !client_secret) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters' });
    }

    const client = clients[client_id];
    if (!client || client.client_secret !== client_secret) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
    }

    const refreshData = refreshTokens.get(refresh_token);
    if (!refreshData || refreshData.client_id !== client_id) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid refresh token' });
    }

    const accessToken = generateRandomString();
    const tokenData = {
      user: refreshData.user,
      client_id,
      scope: refreshData.scope,
      expires_at: Date.now() + 3600000
    };

    accessTokens.set(accessToken, tokenData);

    setTimeout(() => {
      accessTokens.delete(accessToken);
    }, 3600000);

    return res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: 3600,
      scope: refreshData.scope
    });

  } else {
    return res.status(400).json({ error: 'unsupported_grant_type', error_description: 'Grant type not supported' });
  }
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Missing or invalid authorization header' });
  }

  const token = authHeader.substring(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token not found or expired' });
  }

  if (tokenData.expires_at < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token expired' });
  }

  const user = users[tokenData.user];
  if (!user) {
    return res.status(404).json({ error: 'user_not_found' });
  }

  res.json({
    sub: user.email,
    email: user.email,
    name: user.name
  });
});

app.post('/introspect', (req, res) => {
  const { token, client_id, client_secret } = req.body;

  if (!token || !client_id || !client_secret) {
    return res.status(400).json({ error: 'invalid_request' });
  }

  const client = clients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const tokenData = accessTokens.get(token);
  
  if (!tokenData) {
    return res.json({ active: false });
  }

  if (tokenData.expires_at < Date.now()) {
    accessTokens.delete(token);
    return res.json({ active: false });
  }

  res.json({
    active: true,
    client_id: tokenData.client_id,
    username: tokenData.user,
    scope: tokenData.scope,
    exp: Math.floor(tokenData.expires_at / 1000)
  });
});

app.post('/revoke', (req, res) => {
  const { token, token_type_hint, client_id, client_secret } = req.body;

  if (!token || !client_id || !client_secret) {
    return res.status(400).json({ error: 'invalid_request' });
  }

  const client = clients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (token_type_hint === 'refresh_token') {
    refreshTokens.delete(token);
  } else {
    accessTokens.delete(token);
  }

  res.status(200).send();
});

